mapper.select:
select id as id, appointment_no as appointmentNo, owner_user_id as ownerUserId, owner_id as ownerId, pet_id as petId, doctor_id as doctorId, service_item_id as serviceItemId, service_type as serviceType, appointment_time as appointmentTime, symptom_desc as symptomDesc, remark as remark, source_type as sourceType, status as status, status_text as statusText, cancel_reason as cancelReason, verified_by as verifiedBy, verified_time as verifiedTime, create_time as createTime, update_time as updateTime, created_time as createdTime, updated_time as updatedTime, is_deleted as isDeleted from appointment where is_deleted = 0
and status = #{status}
order by id desc
